import { FalseFlag as ff } from "@falseflag/config";

export default ff.flag({
  value_type: "object",
  default: { theme: "auto" },
  rules: [
    ff.rule(
      "dark-mode",
      ff.any(
        ff.eq("user.prefers", "dark"),
        ff.eq("system.color_scheme", "dark"),
      ),
      { theme: "dark" },
    ),
  ],
});
